  ?player p:P463 ?yorkClaim ;
          p:P463 ?newportClaim ;
          p:P1553 ?loanClaim .
  ?yorkClaim ps:P463 wd:Q3435479 .
  ?newportClaim ps:P463 wd:Q2865230 .
  ?loanClaim ps:P1553 wd:Q872353 ;
            pq:P598 ?loaningClub ;
            pq:P580 ?start ;
            pq:P582 ?end .
  FILTER (?start <= "2018-05-31"^^xsd:date && ?end >= "2017-07-01"^^xsd:date) .
